async function process(incomingData, nodeData, params) {
  try {
    const { url, method, headers, timeout } = nodeData;
    const { retryAttempts = 3, retryDelay = 1000 } = params;

    if (!url) {
      throw new Error('URL is required');
    }

    let lastError;

    for (let attempt = 1; attempt <= retryAttempts; attempt++) {
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), timeout || 30000);

        const response = await fetch(url, {
          method: method || 'GET',
          headers: {
            'Accept': 'application/json',
            ...headers
          },
          body: method !== 'GET' && nodeData.body ? JSON.stringify(nodeData.body) : undefined,
          signal: controller.signal
        });

        clearTimeout(timeoutId);

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }

        const data = await response.json();

        return {
          success: true,
          data,
          metadata: {
            status: response.status,
            headers: Object.fromEntries(response.headers),
            timestamp: new Date().toISOString(),
            attempt
          }
        };
      } catch (error) {
        lastError = error;
        if (attempt < retryAttempts) {
          console.log(`Attempt ${attempt} failed, retrying in ${retryDelay}ms...`);
          await new Promise(resolve => setTimeout(resolve, retryDelay));
        }
      }
    }

    throw lastError;
  } catch (error) {
    return {
      success: false,
      error: error.message,
      timestamp: new Date().toISOString()
    };
  }
}
